using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
IDataView allData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

// Map "Yes"/"No" → true/false label, encode Region, concatenate features
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
        (input, output) => output.Label = input.Churned == "Yes", contractName: null)
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// --- Evaluate on test set ---
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}  F1: {metrics.F1Score:F4}  Accuracy: {metrics.Accuracy:F4}");

// Save model for PredictionEnginePool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "churn-model.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);

// --- Register pooled prediction engine (thread-safe) ---
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, PredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = Math.Round(result.Probability, 4)
    });
});

app.Run();

public sealed record PredictRequest(float Age, float Income, string Region, float PurchaseHistory);

public sealed class LabelMapping
{
    public bool Label { get; set; }
}

